def has_cycle_directed(n, edges):
    g = [[] for _ in range(n)]
    for u, v in edges:
        g[u].append(v)
    state = [0] * n
    def dfs(u):
        state[u] = 1
        for v in g[u]:
            if state[v] == 1:
                return True
            if state[v] == 0 and dfs(v):
                return True
        state[u] = 2
        return False
    for i in range(n):
        if state[i] == 0 and dfs(i):
            return True
    return False

